+#ifndef FLASHINFER_MAMBA_SELECTIVE_STATE_UPDATE_CUH_
+#define FLASHINFER_MAMBA_SELECTIVE_STATE_UPDATE_CUH_
+
+#include <cooperative_groups.h>
+#include <cooperative_groups/memcpy_async.h>
+#include <cuda_runtime_api.h>
+
+#include <cmath>
